entity decalper_eb_ot_sdeen_pot_pi_dehcac_xnilix_UART_Core is
  port (
    UART_Tx : out STD_LOGIC;
    Sl_DBus : out STD_LOGIC_VECTOR ( 7 downto 0 );
    Clk : in STD_LOGIC;
    Rst : in STD_LOGIC;
    UART_Rx : in STD_LOGIC;
    Q : in STD_LOGIC_VECTOR ( 4 downto 0 );
    lmb_reg_read : in STD_LOGIC;
    E : in STD_LOGIC_VECTOR ( 0 to 0 );
    D : in STD_LOGIC_VECTOR ( 7 downto 0 );
    GPI_In : in STD_LOGIC_VECTOR ( 0 to 0 );
    io_bus_read_data : in STD_LOGIC_VECTOR ( 7 downto 0 )
  );
end decalper_eb_ot_sdeen_pot_pi_dehcac_xnilix_UART_Core;

architecture STRUCTURE of decalper_eb_ot_sdeen_pot_pi_dehcac_xnilix_UART_Core is
  signal RX_Data : STD_LOGIC_VECTOR ( 6 downto 0 );
  signal UART_Status1 : STD_LOGIC;
  signal \Using_UART_RX.UART_RX_I1_n_1\ : STD_LOGIC;
  signal \Using_UART_RX.UART_RX_I1_n_2\ : STD_LOGIC;
